select 'Swim Performance', 'A 6-week, 3-day supplemental block for swimmers. It builds pulling strength, shoulder durability, hip drive, trunk control, and recovery mobility without adding unnecessary shoulder fatigue.', 6, 3, 'athletic_performance', 'intermediate', true, '{"weeks":[{"label":"Week 1","rep_note":"<b>Base.</b> Supplemental training only. Keep 1-3 reps in reserve and place these sessions after hard sport days or at least 24 hours before key practices.","days":[{"title":"Swim Support A - Pull Strength","sub":"Day 1 - Upper pull, shoulder durability, trunk","groups":[{"name":"PULL STRENGTH","exercises":[{"name":"Pull-Up / Lat Pulldown","sets":3,"reps":"8-10","note":"Full reach, ribs down. Stop short of shoulder irritation.","swap_category":"back_multi"},{"name":"Chest-Supported Row","sets":3,"reps":"10-12","note":"Support the torso so the lats and mid-back do the work.","swap_category":"back_multi"},{"name":"Straight-Arm Pulldown","sets":2,"reps":"10-12","note":"Mimic the catch. Long arms and controlled sweep.","swap_category":"back_single"}]},{"name":"SHOULDER CARE","exercises":[{"name":"Cable Face Pull","sets":2,"reps":"12-15","note":"Rope to forehead. Rotate thumbs back.","swap_category":"shoulders"},{"name":"Band External Rotation","sets":2,"reps":"15 each","note":"Light burn only. Elbow stays close.","swap_category":"shoulders"}]},{"name":"CORE","exercises":[{"name":"Dead Bug","sets":3,"reps":"8 each","note":"Exhale hard. Keep low back quiet.","swap_category":"abs"},{"name":"Side Plank","sets":2,"reps":"30-45s","note":"Long line. Do not sag through the hips.","swap_category":"abs"}]}]},{"title":"Swim Support B - Hips & Trunk","sub":"Day 2 - Lower body strength without shoulder load","groups":[{"name":"LOWER STRENGTH","exercises":[{"name":"Trap Bar Deadlift","sets":3,"reps":"8-10","note":"Brace hard. Moderate load, no grinding.","swap_category":"legs_multi"},{"name":"Rear-Foot Elevated Split Squat","sets":3,"reps":"10-12","note":"Front heel heavy. Smooth depth.","swap_category":"legs_single"},{"name":"Hip Thrust","sets":3,"reps":"10-12","note":"Full hip extension. Pause at top.","swap_category":"legs_single"}]},{"name":"TRUNK CONTROL","exercises":[{"name":"Pallof Press","sets":3,"reps":"10 each","note":"Resist rotation. Ribs down.","swap_category":"abs"},{"name":"Farmer Carry","sets":3,"reps":"30-40m","note":"Tall posture. Quiet shoulders.","swap_category":"traps"}]}]},{"title":"Swim Recovery - Mobility & Prehab","sub":"Day 3 - Low load recovery session","groups":[{"name":"MOBILITY","exercises":[{"name":"Thoracic Rotation","sets":2,"reps":"10 each","note":"Open the chest without forcing the low back.","swap_category":"abs"},{"name":"Lat Stretch","sets":2,"reps":"30-45s","note":"Breathe into the side body.","swap_category":"back_single"},{"name":"Pec Doorway Stretch","sets":2,"reps":"30-45s","note":"Gentle stretch. No numbness or tingling.","swap_category":"chest_single"},{"name":"Scapular Wall Slide","sets":2,"reps":"10-12","note":"Reach up without shrugging.","swap_category":"shoulders"},{"name":"Ankle Rocker Mobility","sets":2,"reps":"10 each","note":"Knee tracks over toes for better kick mechanics.","swap_category":"calves"}]}]}]},{"label":"Week 2","rep_note":"<b>Base.</b> Supplemental training only. Keep 1-3 reps in reserve and place these sessions after hard sport days or at least 24 hours before key practices.","days":[{"title":"Swim Support A - Pull Strength","sub":"Day 1 - Upper pull, shoulder durability, trunk","groups":[{"name":"PULL STRENGTH","exercises":[{"name":"Pull-Up / Lat Pulldown","sets":3,"reps":"8-10","note":"Full reach, ribs down. Stop short of shoulder irritation.","swap_category":"back_multi"},{"name":"Chest-Supported Row","sets":3,"reps":"10-12","note":"Support the torso so the lats and mid-back do the work.","swap_category":"back_multi"},{"name":"Straight-Arm Pulldown","sets":2,"reps":"10-12","note":"Mimic the catch. Long arms and controlled sweep.","swap_category":"back_single"}]},{"na