select 'Cycle Performance', 'A 6-week, 3-day supplemental block for cyclists. It emphasizes posterior chain strength, single-leg control, core stability, and mobility to support riding volume without blunting key bike sessions.', 6, 3, 'athletic_performance', 'intermediate', true, '{"weeks":[{"label":"Week 1","rep_note":"<b>Base.</b> Supplemental training only. Keep 1-3 reps in reserve and place these sessions after hard sport days or at least 24 hours before key practices.","days":[{"title":"Cycling Support A - Max Strength","sub":"Day 1 - Heavy lower body after a hard ride","groups":[{"name":"LOWER STRENGTH","exercises":[{"name":"Front Squat","sets":4,"reps":"8-10","note":"Tall torso. Stop with speed still in the rep.","swap_category":"legs_multi"},{"name":"Romanian Deadlift","sets":3,"reps":"10-12","note":"Hamstrings loaded. Neutral spine.","swap_category":"legs_multi"},{"name":"Bulgarian Split Squat","sets":3,"reps":"10-12","note":"Single-leg force without chasing soreness.","swap_category":"legs_single"}]},{"name":"CALVES","exercises":[{"name":"Standing Calf Raise","sets":3,"reps":"10-12","note":"Full range. Pause at top.","swap_category":"calves"}]},{"name":"CORE","exercises":[{"name":"Plank With Reach","sets":3,"reps":"8 each","note":"Reach without shifting hips.","swap_category":"abs"}]}]},{"title":"Cycling Support B - Single-Leg Balance","sub":"Day 2 - Hip stability and posterior chain","groups":[{"name":"SINGLE-LEG","exercises":[{"name":"Step-Up","sets":3,"reps":"10-12","note":"Drive through full foot. Control the descent.","swap_category":"legs_single"},{"name":"Single-Leg Romanian Deadlift","sets":3,"reps":"10-12","note":"Square hips. Reach long.","swap_category":"legs_single"},{"name":"Hamstring Curl","sets":3,"reps":"10-12","note":"Controlled negative. No hip lift.","swap_category":"legs_single"}]},{"name":"ADDUCTORS & CORE","exercises":[{"name":"Copenhagen Plank","sets":2,"reps":"20-30s each","note":"Short lever if needed. Keep hips high.","swap_categ