select 'Run Performance', 'A 6-week, 3-day supplemental block for runners. It targets tissue durability, calves and soleus, hip control, low-volume elasticity, and mobility so strength work supports mileage instead of competing with it.', 6, 3, 'athletic_performance', 'intermediate', true, '{"weeks":[{"label":"Week 1","rep_note":"<b>Base.</b> Supplemental training only. Keep 1-3 reps in reserve and place these sessions after hard sport days or at least 24 hours before key practices.","days":[{"title":"Run Support A - Strength & Tendons","sub":"Day 1 - Durable legs after workout day","groups":[{"name":"LOWER STRENGTH","exercises":[{"name":"Trap Bar Deadlift","sets":3,"reps":"8-10","note":"Strong but not maximal. Leave reps in reserve.","swap_category":"legs_multi"},{"name":"Rear-Foot Elevated Split Squat","sets":3,"reps":"10-12","note":"Control knee track and hip position.","swap_category":"legs_single"}]},{"name":"LOWER LEG","exercises":[{"name":"Standing Calf Raise","sets":3,"reps":"8-12","note":"Heavy enough to matter. Full range.","swap_category":"calves"},{"name":"Soleus Raise","sets":3,"reps":"12-15","note":"Bent knee. Pause at the top.","swap_category":"calves"},{"name":"Tibialis Raise","sets":2,"reps":"15-20","note":"Lift toes toward shins.","swap_category":"calves"}]},{"name":"CORE","exercises":[{"name":"Side Plank","sets":2,"reps":"30-45s","note":"Pelvis stacked. Breathe calmly.","swap_category":"abs"}]}]},{"title":"Run Support B - Elasticity & Control","sub":"Day 2 - Low-volume plyometrics and hip stability","groups":[{"name":"STABILITY","exercises":[{"name":"Step-Down","sets":3,"reps":"8 each","note":"Slow lower. Knee tracks over toes.","swap_category":"legs_single"},{"name":"Single-Leg Romanian Deadlift","sets":3,"reps":"10-12","note":"Balance first, load second.","swap_category":"legs_single"},{"name":"Lateral Lunge","sets":2,"reps":"6 each","note":"Load the hip. Keep trail leg long.","swap_category":"legs_single"}]},{"name":"ELASTICITY","exercises":[{"