 Squat","note":"Great low-soreness substitute."},{"name":"Romanian Deadlift","note":"Hinge from hips. Hamstrings loaded."}],"legs_single":[{"name":"Step-Up","note":"Drive through full foot. Control down."},{"name":"Split Squat","note":"Vertical shin if knees are sensitive."},{"name":"Single-Leg RDL","note":"Square hips. Reach long through back leg."},{"name":"Lateral Lunge","note":"Sit into hip. Trail leg stays long."}],"calves":[{"name":"Standing Calf Raise","note":"Full stretch, full rise, controlled tempo."},{"name":"Soleus Raise","note":"Knee bent. Pause at top."},{"name":"Tibialis Raise","note":"Lean against wall. Lift toes toward shins."}],"back_multi":[{"name":"Chest-Supported Row","note":"No low-back cost. Pull elbows back."},{"name":"Seated Cable Row","note":"Tall chest. Pause at the body."},{"name":"Pull-Up / Lat Pulldown","note":"Lead elbows down, not chin up."},{"name":"1-Arm DB Row","note":"Support on bench. Pull elbow to hip."}],"back_single":[{"name":"Straight-Arm Pulldown","note":"Arms long. Feel lats, not triceps."},{"name":"Band Pulldown","note":"Easy recovery-day pulling option."},{"name":"Cable Row ISO Hold","note":"Hold squeeze without leaning back."}],"traps":[{"name":"Farmer Carry","note":"Heavy enough to challenge posture."},{"name":"Suitcase Carry","note":"One side loaded. Do not lean."},{"name":"DB Shrug","note":"Lift straight up. No rolling."}],"biceps":[{"name":"DB Hammer Curl","note":"Neutral grip. Elbow-friendly."},{"name":"Cable Curl","note":"Constant tension and clean tempo."},{"name":"EZ-Bar Curl","note":"Use if wrists prefer angled grip."}]}}'::jsonb
